SELECT rcmmd_track_rank_table.rcmmd_id, rcmmd_track_rank_table.rcmmd_disp_sn, rcmmd_track_rank_table.track_id, rcmmd_track_rank_table.track_nm, rcmmd_track_rank_table.disp_sn, rcmmd_track_rank_table.reprsnt_artist_id, rcmmd_track_rank_table.agency_id, rcmmd_track_rank_table.create_dtime, rcmmd_track_rank_table.update_dtime, rcmmd_track_rank_table.img_size, rcmmd_track_rank_table.img_url, rcmmd_track_rank_table.rcmmdCreateDtime, rcmmd_track_rank_table.svc_genre_id, rcmmd_track_rank_table.svc_genre_nm, rcmmd_track_rank_table.trackCount, d.artist_id, d.artist_nm, a.album_id, b.album_img_size size, b.album_img_url url, e.artist_id reqArtistId, e.artist_nm reqArtistNm, rank FROM ( -- 4. rcmmd_rank_table start SELECT @curRank:=IF(@prevRcmmdId = rcmmd_track_table.rcmmd_id, @curRank + 1, 1) AS rank, @prevRcmmdId:=rcmmd_track_table.rcmmd_id, rcmmd_track_table.rcmmd_id, rcmmd_track_table.rcmmd_disp_sn, rcmmd_track_table.track_id, rcmmd_track_table.track_nm, rcmmd_track_table.disp_sn, rcmmd_track_table.album_id, rcmmd_track_table.reprsnt_artist_id, rcmmd_track_table.agency_id, rcmmd_track_table.create_dtime, rcmmd_track_table.update_dtime, rcmmd_track_table.img_size, rcmmd_track_table.img_url, rcmmd_track_table.rcmmdCreateDtime, rcmmd_track_table.svc_genre_id, rcmmd_track_table.svc_genre_nm, rcmmd_track_table.trackCount FROM ( -- 3. rcmmd_track_table start SELECT rcmmd_img_table.rcmmd_id, rcmmd_img_table.svc_genre_id, rcmmd_img_table.svc_genre_nm, rcmmd_img_table.disp_sn rcmmd_disp_sn, rcmmd_img_table.img_size, rcmmd_img_table.img_url, rcmmd_img_table.rcmmdCreateDtime, rcmmd_img_table.trackCount, b.track_id, b.disp_sn, c.album_id, c.track_nm, c.reprsnt_artist_id, c.agency_id, c.create_dtime, c.update_dtime FROM ( -- 2. rcmmd_img_table start SELECT rcmmd_table.rcmmd_id, rcmmd_table.svc_genre_id, rcmmd_table.svc_genre_nm, rcmmd_table.disp_sn, rcmmd_table.rcmmdCreateDtime, rcmmd_table.trackCount, b.img_size, b.img_url FROM ( -- 1. rcmmd_table start SELECT rcmmd_prefer_genre_similar_track_id rcmmd_id, a.svc_genre_id, b.svc_genre_nm, disp_sn, CASE DAYOFWEEK(NOW()) WHEN '1' THEN 'SUN' WHEN '2' THEN 'MON' WHEN '3' THEN 'TUE' WHEN '4' THEN 'WED' WHEN '5' THEN 'THU' WHEN '6' THEN 'FRI' WHEN '7' THEN 'SAT' END AS week, a.create_dtime rcmmdCreateDtime, ( SELECT COUNT(*) FROM tb_rcmmd_prefer_genre_similar_track_list aa JOIN tb_track bb ON aa.track_id = bb.track_id AND bb.disp_status_yn = 'Y' AND now() BETWEEN bb.disp_start_dtime AND bb.disp_end_dtime WHERE aa.rcmmd_prefer_genre_similar_track_id = a.rcmmd_prefer_genre_similar_track_id ) trackCount FROM tb_rcmmd_prefer_genre_similar_track a INNER JOIN tb_svc_genre b ON a.svc_genre_id = b.svc_genre_id WHERE rcmmd_prefer_genre_similar_track_id IN
#{rcmmdId}
ORDER BY FIELD(rcmmd_id,
#{rcmmdId} ), disp_sn LIMIT #{recommendLimitSize} -- 1. rcmmd_table end ) rcmmd_table LEFT OUTER JOIN tb_map_img_rcmmd_img b ON rcmmd_table.svc_genre_id = b.img_content_id AND b.img_content_type = 'GENRE' AND b.rcmmd_type_id = 'RC_GR_TR' AND b.os_type = #{osType} AND b.dfk_type = rcmmd_table.week AND b.img_disp_type = 'MAIN_TOP' ORDER BY rcmmd_table.disp_sn
-- 2. rcmmd_img_table end ) rcmmd_img_table INNER JOIN tb_rcmmd_prefer_genre_similar_track_list b ON rcmmd_img_table.rcmmd_id = b.rcmmd_prefer_genre_similar_track_id INNER JOIN tb_track c ON b.track_id = c.track_id JOIN (SELECT @curRank:=0, @prevRcmmdId:=0) r WHERE c.disp_status_yn = 'Y' AND now() BETWEEN c.disp_start_dtime AND c.disp_end_dtime ORDER BY rcmmd_img_table.rcmmd_id , b.disp_sn -- 3. rcmmd_track_table end ) rcmmd_track_table -- 4. rcmmd_tank_table end ) rcmmd_track_rank_table INNER JOIN ted_album a ON rcmmd_track_rank_table.album_id = a.album_id AND a.disp_status_yn= 'Y' AND now() BETWEEN a.disp_start_dtime AND a.disp_end_dtime LEFT OUTER JOIN tb_album_img b ON a.album_id = b.album_id LEFT OUTER JOIN ted_trackartist c ON rcmmd_track_rank_table.track_id =c.track_id AND c.rp_yn = 'Y' LEFT OUTER JOIN ted_artist d ON c.artist_id = d.artist_id LEFT OUTER JOIN ted_artist e ON e.artist_id = rcmmd_track_rank_table.reprsnt_artist_id WHERE rank <= #{trackLimitSize}

SELECT rcmmd_track_rank_table.rcmmd_id, rcmmd_track_rank_table.rcmmd_disp_sn, rcmmd_track_rank_table.track_id, rcmmd_track_rank_table.track_nm, rcmmd_track_rank_table.disp_sn, rcmmd_track_rank_table.reprsnt_artist_id, rcmmd_track_rank_table.agency_id, rcmmd_track_rank_table.create_dtime, rcmmd_track_rank_table.update_dtime, rcmmd_track_rank_table.img_size, rcmmd_track_rank_table.img_url, rcmmd_track_rank_table.rcmmdCreateDtime, rcmmd_track_rank_table.svc_genre_id, rcmmd_track_rank_table.svc_genre_nm, rcmmd_track_rank_table.trackCount, d.artist_id, d.artist_nm, a.album_id, b.album_img_size size, b.album_img_url url, e.artist_id reqArtistId, e.artist_nm reqArtistNm, rank FROM ( -- 4. rcmmd_rank_table start SELECT @curRank:=IF(@prevRcmmdId = rcmmd_track_table.rcmmd_id, @curRank + 1, 1) AS rank, @prevRcmmdId:=rcmmd_track_table.rcmmd_id, rcmmd_track_table.rcmmd_id, rcmmd_track_table.rcmmd_disp_sn, rcmmd_track_table.track_id, rcmmd_track_table.track_nm, rcmmd_track_table.disp_sn, rcmmd_track_table.album_id, rcmmd_track_table.reprsnt_artist_id, rcmmd_track_table.agency_id, rcmmd_track_table.create_dtime, rcmmd_track_table.update_dtime, rcmmd_track_table.img_size, rcmmd_track_table.img_url, rcmmd_track_table.rcmmdCreateDtime, rcmmd_track_table.svc_genre_id, rcmmd_track_table.svc_genre_nm, rcmmd_track_table.trackCount FROM ( -- 3. rcmmd_track_table start SELECT rcmmd_img_table.rcmmd_id, rcmmd_img_table.svc_genre_id, rcmmd_img_table.svc_genre_nm, rcmmd_img_table.disp_sn rcmmd_disp_sn, rcmmd_img_table.img_size, rcmmd_img_table.img_url, rcmmd_img_table.rcmmdCreateDtime, rcmmd_img_table.trackCount, b.track_id, b.disp_sn, c.album_id, c.track_nm, c.reprsnt_artist_id, c.agency_id, c.create_dtime, c.update_dtime FROM ( -- 2. rcmmd_img_table start SELECT rcmmd_table.rcmmd_id, rcmmd_table.svc_genre_id, rcmmd_table.svc_genre_nm, rcmmd_table.disp_sn, rcmmd_table.rcmmdCreateDtime, rcmmd_table.trackCount, b.img_size, b.img_url FROM ( -- 1. rcmmd_table start SELECT rcmmd_similar_track_id rcmmd_id, 0 as svc_genre_id, '' as svc_genre_nm, disp_sn, CASE DAYOFWEEK(NOW()) WHEN '1' THEN 'SUN' WHEN '2' THEN 'MON' WHEN '3' THEN 'TUE' WHEN '4' THEN 'WED' WHEN '5' THEN 'THU' WHEN '6' THEN 'FRI' WHEN '7' THEN 'SAT' END AS week, a.create_dtime rcmmdCreateDtime, a.disp_sn panel_disp_sn, ( SELECT COUNT(*) FROM tb_rcmmd_similar_track_list aa JOIN tb_track bb ON bb.track_id = aa.track_id AND bb.disp_status_yn = 'Y' AND now() BETWEEN bb.disp_start_dtime AND bb.disp_end_dtime WHERE aa.rcmmd_similar_track_id = a.rcmmd_similar_track_id ) trackCount FROM tb_rcmmd_similar_track a WHERE rcmmd_similar_track_id IN
#{rcmmdId}
ORDER BY FIELD(rcmmd_id,
#{rcmmdId}
), disp_sn LIMIT #{recommendLimitSize} -- 1. rcmmd_table end; ) rcmmd_table LEFT OUTER JOIN tb_rcmmd_img_mang b ON rcmmd_table.week = b.dfk_type AND rcmmd_table.panel_disp_sn = b.disp_sn AND b.rcmmd_type_id = 'RC_SML_TR' AND b.img_disp_type = 'MAIN_TOP' AND b.os_type = #{osType} ORDER BY rcmmd_table.disp_sn
-- 2. rcmmd_img_table end ) rcmmd_img_table INNER JOIN tb_rcmmd_similar_track_list b ON rcmmd_img_table.rcmmd_id = b.rcmmd_similar_track_id INNER JOIN tb_track c ON b.track_id = c.track_id JOIN (SELECT @curRank:=0, @prevRcmmdId:=0) r WHERE c.disp_status_yn = 'Y' AND now() BETWEEN c.disp_start_dtime AND c.disp_end_dtime ORDER BY rcmmd_img_table.rcmmd_id , b.disp_sn -- 3. rcmmd_track_table end ) rcmmd_track_table -- 4. rcmmd_tank_table end ) rcmmd_track_rank_table JOIN ted_album a ON rcmmd_track_rank_table.album_id = a.album_id AND a.disp_status_yn= 'Y' AND now() BETWEEN a.disp_start_dtime AND a.disp_end_dtime LEFT OUTER JOIN tb_album_img b ON a.album_id = b.album_id LEFT OUTER JOIN ted_trackartist c ON rcmmd_track_rank_table.track_id =c.track_id AND c.rp_yn = 'Y' LEFT OUTER JOIN ted_artist d ON c.artist_id = d.artist_id LEFT OUTER JOIN ted_artist e ON e.artist_id = rcmmd_track_rank_table.reprsnt_artist_id WHERE rank <= #{trackLimitSize}

SELECT rcmmd_track_rank_table.rcmmd_id, rcmmd_track_rank_table.rcmmd_disp_sn, rcmmd_track_rank_table.track_id, rcmmd_track_rank_table.track_nm, rcmmd_track_rank_table.disp_sn, rcmmd_track_rank_table.reprsnt_artist_id, rcmmd_track_rank_table.agency_id, rcmmd_track_rank_table.create_dtime, rcmmd_track_rank_table.update_dtime, rcmmd_track_rank_table.img_size, rcmmd_track_rank_table.img_url, rcmmd_track_rank_table.svc_genre_id, rcmmd_track_rank_table.svc_genre_nm, rcmmd_track_rank_table.trackCount, rcmmd_track_rank_table.rcmmdCreateDtime, d.artist_id, d.artist_nm, a.album_id, b.album_img_size size, b.album_img_url url, e.artist_id reqArtistId, e.artist_nm reqArtistNm, rank FROM ( -- 4. rcmmd_rank_table start SELECT @curRank:=IF(@prevRcmmdId = rcmmd_track_table.rcmmd_id, @curRank + 1, 1) AS rank, @prevRcmmdId:=rcmmd_track_table.rcmmd_id, rcmmd_track_table.rcmmd_id, rcmmd_track_table.rcmmd_disp_sn, rcmmd_track_table.track_id, rcmmd_track_table.track_nm, rcmmd_track_table.disp_sn, rcmmd_track_table.album_id, rcmmd_track_table.reprsnt_artist_id, rcmmd_track_table.agency_id, rcmmd_track_table.create_dtime, rcmmd_track_table.update_dtime, rcmmd_track_table.img_size, rcmmd_track_table.img_url, rcmmd_track_table.svc_genre_id, rcmmd_track_table.svc_genre_nm, rcmmd_track_table.trackCount, rcmmd_track_table.rcmmdCreateDtime FROM ( SELECT -- 3. rcmmd_track_table starSELECT rcmmd_img_table.rcmmd_id, rcmmd_img_table.svc_genre_id, rcmmd_img_table.svc_genre_nm, rcmmd_img_table.disp_sn rcmmd_disp_sn, rcmmd_img_table.img_size, rcmmd_img_table.img_url, rcmmd_img_table.trackCount, rcmmd_img_table.rcmmdCreateDtime, b.track_id, b.disp_sn, c.track_nm, c.album_id, c.reprsnt_artist_id, c.agency_id, c.create_dtime, c.update_dtime FROM ( -- 2. rcmmd_img_table start SELECT rcmmd_table.rcmmd_id, rcmmd_table.svc_genre_id, rcmmd_table.svc_genre_nm, rcmmd_table.disp_sn, rcmmd_table.trackCount, rcmmd_table.rcmmdCreateDtime, b.img_size, b.img_url FROM ( -- 1. rcmmd_table start SELECT rcmmd_mforu_id rcmmd_id, a.svc_genre_id, b.svc_genre_nm, disp_sn, ( SELECT COUNT(*) FROM tb_rcmmd_mforu_list aa JOIN tb_track bb ON aa.track_id = bb.track_id AND bb.disp_status_yn = 'Y' AND now() BETWEEN bb.disp_start_dtime AND bb.disp_end_dtime WHERE aa.rcmmd_mforu_id = a.rcmmd_mforu_id ) trackCount, a.disp_std_start_dt rcmmdCreateDtime FROM tb_rcmmd_mforu a INNER JOIN tb_svc_genre b ON a.svc_genre_id = b.svc_genre_id WHERE rcmmd_mforu_id IN
#{rcmmdId}
ORDER BY FIELD(rcmmd_id,
#{rcmmdId}
), disp_sn LIMIT #{recommendLimitSize} -- 1. rcmmd_table end; ) rcmmd_table LEFT OUTER JOIN tb_map_img_rcmmd_img b ON rcmmd_table.svc_genre_id = b.img_content_id AND b.rcmmd_type_id = 'RC_CF_TR' AND b.os_type = #{osType} AND b.img_disp_type = 'MAIN_TOP' AND b.img_content_type = 'GENRE'
ORDER BY rcmmd_table.disp_sn -- 2. rcmmd_img_table end ) rcmmd_img_table INNER JOIN tb_rcmmd_mforu_list b ON rcmmd_img_table.rcmmd_id = b.rcmmd_mforu_id INNER JOIN tb_track c ON b.track_id = c.track_id JOIN (SELECT @curRank:=0, @prevRcmmdId:=0) r WHERE c.disp_status_yn = 'Y'AND now() BETWEEN c.disp_start_dtime AND c.disp_end_dtime ORDER BY rcmmd_img_table.rcmmd_id , b.disp_sn -- 3. rcmmd_track_table end ) rcmmd_track_table -- 4. rcmmd_tank_table end ) rcmmd_track_rank_table JOIN ted_album a ON rcmmd_track_rank_table.album_id = a.album_id AND a.disp_status_yn= 'Y' AND now() BETWEEN a.disp_start_dtime AND a.disp_end_dtime LEFT OUTER JOIN tb_album_img b ON a.album_id = b.album_id LEFT OUTER JOIN ted_trackartist c ON rcmmd_track_rank_table.track_id =c.track_id AND c.rp_yn = 'Y' LEFT OUTER JOIN ted_artist d ON c.artist_id = d.artist_id LEFT OUTER JOIN ted_artist e ON e.artist_id = rcmmd_track_rank_table.reprsnt_artist_id WHERE rank <= #{trackLimitSize};

SELECT ARTIST_ID , SIMILAR_ARTIST_ID FROM TB_SIMILAR_ARTIST WHERE ARTIST_ID IN
#{artistId}
AND SIMILAR_ARTIST_ID NOT IN
#{artistId}

SELECT TT.REPRSNT_ARTIST_ID AS ARTIST_ID , TT.TRACK_ID , TT.TRACK_NM FROM TB_TRACK TT INNER JOIN ( SELECT REPRSNT_ARTIST_ID , group_concat(TRACK_ID) AS GROUP_TRACK_ID FROM ( SELECT TRACK_ID , TRACK_NM , TRACK_POPULARITY , REPRSNT_ARTIST_ID , RNUM FROM ( SELECT A.* , (CASE @VARTISTID WHEN A.REPRSNT_ARTIST_ID THEN @ROWNUM := @ROWNUM + 1 ELSE @ROWNUM := 1 END) AS RNUM , (@VARTISTID := A.REPRSNT_ARTIST_ID) AS VJOB FROM TB_TRACK A, ( SELECT @VARTISTID := '' , @ROWNUM := 0 FROM DUAL) B WHERE REPRSNT_ARTIST_ID IN
#{artistId}
AND A.DISP_STATUS_YN = 'Y' ORDER BY A.REPRSNT_ARTIST_ID, A.TRACK_POPULARITY DESC ) C WHERE RNUM < 31 ORDER BY rand()) D GROUP BY REPRSNT_ARTIST_ID) I ON TT.REPRSNT_ARTIST_ID = I.REPRSNT_ARTIST_ID AND find_in_set(TT.TRACK_ID, I.GROUP_TRACK_ID) BETWEEN 1 AND 2

SELECT T1.TRACK_ID, T1.SIMILAR_TRACK_ID FROM TB_SIMILAR_TRACK T1 INNER JOIN TB_TRACK T2 ON T1.TRACK_ID = T2.TRACK_ID AND T2.DISP_STATUS_YN = 'Y' WHERE T1.TRACK_ID IN
#{trackId}
ORDER BY T1.TRACK_ID, T1.RANK

SELECT c.img_url FROM
tb_rcmmd_img_mang c WHERE c.dfk_type = CASE DAYOFWEEK(NOW()) WHEN '1' THEN 'SUN' WHEN '2' THEN 'MON' WHEN '3' THEN 'TUE' WHEN '4' THEN 'WED' WHEN '5' THEN 'THU' WHEN '6' THEN 'FRI' WHEN '7' THEN 'SAT' END AND c.disp_sn = #{dispSn} AND c.rcmmd_type_id = 'RC_SML_TR' AND c.img_disp_type = 'MAIN_TOP' AND c.os_type = #{osType} ORDER BY c.disp_sn LIMIT 1
tb_rcmmd_prefer_genre_similar_track a INNER JOIN tb_svc_genre b ON a.svc_genre_id = b.svc_genre_id LEFT OUTER JOIN tb_map_img_rcmmd_img c ON b.svc_genre_id = c.img_content_id AND c.img_content_type = 'GENRE' AND c.rcmmd_type_id = 'RC_GR_TR' AND c.os_type = #{osType} AND c.dfk_type = CASE DAYOFWEEK(NOW()) WHEN '1' THEN 'SUN' WHEN '2' THEN 'MON' WHEN '3' THEN 'TUE' WHEN '4' THEN 'WED' WHEN '5' THEN 'THU' WHEN '6' THEN 'FRI' WHEN '7' THEN 'SAT' END AND c.img_disp_type = 'MAIN_TOP' WHERE a.rcmmd_prefer_genre_similar_track_id = #{rcmmdId}
LIMIT 1
tb_rcmmd_mforu a INNER JOIN tb_svc_genre b ON a.svc_genre_id = b.svc_genre_id LEFT OUTER JOIN tb_map_img_rcmmd_img c ON b.svc_genre_id = c.img_content_id AND c.rcmmd_type_id = 'RC_CF_TR' AND c.os_type = #{osType} AND c.img_disp_type = 'MAIN_TOP' AND c.img_content_type = 'GENRE'
WHERE rcmmd_mforu_id = #{rcmmdId}
